    if not array:
        return ""
    longest_prefix = ""
    for i in range(len(array[0])):
        prefix = array[0][:i+1]
        for string in array:
            if not string.startswith(prefix):
                return longest_prefix
        longest_prefix = prefix
    return longest_prefix

